// ---- inline PRNG (xorshift64*) — avoids a `rand` dependency -----------------

fn rng_state() -> &'static Mutex<u64> {
    static STATE: OnceLock<Mutex<u64>> = OnceLock::new();
    STATE.get_or_init(|| {
        let seed = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_nanos() as u64)
            .unwrap_or(0x9E3779B97F4A7C15)
            | 1;
        Mutex::new(seed)
    })
}

fn next_u64() -> u64 {
    let mut s = rng_state().lock().unwrap();
    let mut x = *s;
    x ^= x << 13;
    x ^= x >> 7;
    x ^= x << 17;
    *s = x;
    x
}

fn pick(array: &[&str]) -> String {
    if array.is_empty() {
        return String::new();
    }
    let idx = (next_u64() % array.len() as u64) as usize;
    array[idx].to_string()
}

fn random_integer() -> i64 {
    (next_u64() % 100_000) as i64
}

fn random_string() -> String {
    format!("rnd{}", random_integer())
}

fn random_five_digit() -> String {
    let n = 10_000 + (next_u64() % 90_000);
    format!("{:05}", n)
}

fn random_float() -> f64 {
    (next_u64() as f64 / u64::MAX as f64) * 10_000.0
}

fn os_user() -> String {
    std::env::var("USER")
        .or_else(|_| std::env::var("USERNAME"))
        .unwrap_or_else(|_| "unknown".to_string())
}

pub struct BaseTest;

impl BaseTest {
    /// Produce a test value for a column, as a serde_json::Value matching the
    /// domain object's storage convention.
    /// `max_len` is the column's CHARACTER_MAXIMUM_LENGTH as a string (empty for
    /// unbounded types). Character values are truncated to fit so the test data
    /// never overflows the column; numeric/date values (stored as strings) are
    /// never truncated.
    pub fn get_test_data(base: &BaseObject, data_type: &str, test_data_set: &str, max_len: &str) -> Value {
        let base_dt = data_type.split('(').next().unwrap_or(data_type).trim().to_string();
        let limit = max_len.trim().parse::<usize>().ok();

        match test_data_set {
            "firstnames" => Value::String(fit(pick(FIRST_NAMES), limit)),
            "lastnames" => Value::String(fit(pick(LAST_NAMES), limit)),
            "companies" => Value::String(fit(pick(COMPANY_NAMES), limit)),
            "phoneNumbers" => Value::String(fit(pick(PHONE_NUMBERS), limit)),
            "addresses" => Value::String(fit(pick(ADDRESSES), limit)),
            "cities" => Value::String(fit(pick(CITIES), limit)),
            "states" => Value::String(fit(pick(STATES), limit)),
            "emailAddresses" => {
                let f = base.get("first_name");
                let l = base.get("last_name");
                let fs = f.as_str().unwrap_or_default().to_lowercase();
                let ls = l.as_str().unwrap_or_default().to_lowercase();
                Value::String(fit(format!("{}.{}@example.com", fs, ls), limit))
            }
            "principalnames" => {
                let f = base.get("first_name");
                let l = base.get("last_name");
                let fs = f.as_str().unwrap_or_default();
                let ls = l.as_str().unwrap_or_default();
                let initial = fs.chars().next().map(|c| c.to_string()).unwrap_or_default();
                Value::String(fit(format!("{}{}", initial, ls).to_lowercase(), limit))
            }
            "zipcodes" => Value::String(fit(random_five_digit(), limit)),
            "os_user" => Value::String(fit(os_user(), limit)),
            // "random" and any app-specific set fall back to type-based data.
            _ => gen_by_sql_type(&base_dt, limit),
        }
    }

    pub fn add_last_id(domain_obj: &str, id: i64) {
        last_id_map().lock().unwrap().insert(domain_obj.to_string(), id);
    }

    pub fn get_last_id(domain_obj: &str) -> i64 {
        last_id_map()
            .lock()
            .unwrap()
            .get(domain_obj)
            .copied()
            .unwrap_or(0)
    }

    /// Confirm that a freshly re-selected row (`persisted`, the JSON returned
    /// by a `get` dispatch) carries the same values the test wrote (`expected`,
    /// the `LogicContext::transaction` handed to `insert`/`update`), for each
    /// column named in `fields`. Catches bugs where insert/update reports
    /// success but the database ends up with different data than what was
    /// sent (wrong column mapping, silent truncation, a write that never
    /// actually committed, etc.) — the in-memory object alone can't tell you
    /// that; only a separate read-back can.
    pub fn assert_persisted(
        label: &str,
        expected: &BaseObject,
        persisted: &Value,
        fields: &[&str],
    ) -> Result<(), LogicError> {
        if persisted.is_null() {
            return Err(LogicError::Event(format!(
                "{}: row not found when re-selecting by id",
                label
            )));
        }
        for field in fields.iter().copied() {
            let expected_value = expected.get(field);
            let actual_value = persisted.get(field).cloned().unwrap_or(Value::Null);
            if !values_match(&expected_value, &actual_value) {
                return Err(LogicError::Event(format!(
                    "{}: column '{}' mismatch — wrote {} but database has {}",
                    label, field, expected_value, actual_value
                )));
            }
        }
        Ok(())
    }
}

/// Loose equality between a value the test wrote and the value the database
/// returned for the same column. Plain `==` is too strict here: NUMERIC
/// columns round-trip as text on the way in but come back coerced to a JSON
/// number, and float columns can lose a little precision in storage — neither
/// is a persistence bug worth failing the test over.
fn values_match(expected: &Value, actual: &Value) -> bool {
    match (expected, actual) {
        (Value::Null, Value::Null) => true,
        (Value::Bool(a), Value::Bool(b)) => a == b,
        (Value::Bool(a), Value::Number(b)) | (Value::Number(b), Value::Bool(a)) => {
            *a == (b.as_i64().unwrap_or(0) != 0)
        }
        (Value::Number(a), Value::Number(b)) => match (a.as_i64(), b.as_i64()) {
            (Some(ai), Some(bi)) => ai == bi,
            _ => match (a.as_f64(), b.as_f64()) {
                (Some(af), Some(bf)) => approx_eq(af, bf),
                _ => a == b,
            },
        },
        (Value::String(a), Value::String(b)) => a == b,
        (Value::String(a), Value::Number(b)) | (Value::Number(b), Value::String(a)) => a
            .parse::<f64>()
            .ok()
            .zip(b.as_f64())
            .map(|(af, bf)| approx_eq(af, bf))
            .unwrap_or(false),
        _ => expected == actual,
    }
}

/// Relative-tolerance float comparison (absolute below 1.0), generous enough
/// to absorb float4/float8 storage rounding without masking a real mismatch.
fn approx_eq(a: f64, b: f64) -> bool {
    (a - b).abs() <= 1e-3 * a.abs().max(b.abs()).max(1.0)
}

fn gen_by_sql_type(base_dt: &str, limit: Option<usize>) -> Value {
    match base_dt.to_uppercase().as_str() {
        "BIGINT" => Value::from(random_integer()),
        "INTEGER" | "SMALLINT" => Value::from(random_integer()),
        "BYTEA" => Value::Array(Vec::new()),
        "BOOLEAN" => Value::Bool(next_u64() % 2 == 0),
        "DATE" | "TIMESTAMP" | "TIMESTAMP WITH TIME ZONE" | "TIMESTAMPTZ" => {
            Value::String(now_timestamp())
        }
        "NUMERIC" => Value::String(format!("{:.4}", random_float())),
        "DOUBLE PRECISION" | "MONEY" | "REAL" => serde_json::json!(random_float()),
        // Only character types are length-bounded; truncate to fit.
        "CHAR" | "TEXT" | "VARCHAR" => Value::String(fit(random_string(), limit)),
        other => panic!("Cannot generate data for {}", other),
    }
}

/// Truncate a character value to `limit` chars (UTF-8 safe). No limit when None.
fn fit(s: String, limit: Option<usize>) -> String {
    match limit {
        Some(n) if s.chars().count() > n => s.chars().take(n).collect(),
        _ => s,
    }
}

fn now_timestamp() -> String {
    chrono::Local::now()
        .naive_local()
        .format("%Y-%m-%dT%H:%M:%S%.f")
        .to_string()
}

fn last_id_map() -> &'static Mutex<HashMap<String, i64>> {
    static MAP: OnceLock<Mutex<HashMap<String, i64>>> = OnceLock::new();
    MAP.get_or_init(|| Mutex::new(HashMap::new()))
}
